on start
{
  dword adapterCount;
  dword ifIndex;
  long channel;
  adapterCount = ipGetAdapterCount();

  for(ifIndex = 1; ifIndex <= adapterCount; ifIndex++)
  {
    channel = IpGetAdapterChannel (ifIndex);
    if(channel != 0)
    {
      write("Adapter %d is attached to channel %d", ifIndex, channel);
    }
  }
}
